private void xrTableCell33_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // --- Declare running total variables (outside or static in the class scope if cumulative across rows) ---
decimal counterTotal = 0;
decimal doa = 0;
decimal culls = 0;
decimal scaleWeight = 0;

// --- Read values safely from the current record ---
if (GetCurrentColumnValue("CounterTotal") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("CounterTotal").ToString()))
{
    counterTotal = Convert.ToDecimal(GetCurrentColumnValue("CounterTotal"));
}

if (GetCurrentColumnValue("DOA") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("DOA").ToString()))
{
    doa = Convert.ToDecimal(GetCurrentColumnValue("DOA"));
}

if (GetCurrentColumnValue("Culls") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("Culls").ToString()))
{
    culls = Convert.ToDecimal(GetCurrentColumnValue("Culls"));
}

if (GetCurrentColumnValue("ScaleWeight") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("ScaleWeight").ToString()))
{
    scaleWeight = Convert.ToDecimal(GetCurrentColumnValue("ScaleWeight"));
}

// --- Accumulate totals across all records (these must be declared as class-level variables above the method) ---
counterTotalSum += counterTotal;
doaSum += doa;
cullsSum += culls;
scaleWeightSum += scaleWeight;

// --- Compute denominator and final result ---
decimal denominator = counterTotalSum + doaSum + cullsSum;
decimal result = 0;

if (counterTotalSum > 0 && denominator != 0)
    result = scaleWeightSum / denominator;
else
    result = 0;

// --- Assign result to table cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = result.ToString("N2");  // format with 2 decimal places

}

private void xrTableCell72_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
            //-- new logic for Pluck Reject Percentage
// --- Declare variables ---
decimal counterTotal = 0;
decimal pluckReject = 0;
decimal result = 0;

// --- Read values safely ---
if (GetCurrentColumnValue("CounterTotal") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("CounterTotal").ToString()))
{
    counterTotal = Convert.ToDecimal(GetCurrentColumnValue("CounterTotal"));
}

if (GetCurrentColumnValue("PluckReject") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("PluckReject").ToString()))
{
    pluckReject = Convert.ToDecimal(GetCurrentColumnValue("PluckReject"));
}

// --- Equation (same as Iif([CounterTotal] != 0, [PluckReject] / [CounterTotal] * 100, 0)) ---
if (counterTotal != 0)
    result = (pluckReject / counterTotal) * 100;
else
    result = 0;

// --- Optional: accumulate total ---
pluckRejectPercentTotal += result;
// --- Assign result to table cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = result.ToString("N2");  // format with 2 decimal places

}

private void xrTableCell24_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
