decimal deplationSum = 0;

rfFemaleStartedSum += rfFemaleStarted;
deplationSum += deplation;

// --- Equation (same as Iif(Sum(...) <> 0, Sum(DEPLATION)/Sum(rf_Female_Started)*100, 0)) ---
